267:     template <typename Unit>
268:     void holdUnits(EntryUnits<Unit> units) {
269:       MOZ_ASSERT(!cache_);
270:       MOZ_ASSERT(!sourceChunk_.valid());
271:       MOZ_ASSERT(!data_);
272: 
273:       data_ = ToSourceData(std::move(units));
274:     }
