276:    private:
277:     void holdEntry(UncompressedSourceCache* cache,
278:                    const ScriptSourceChunk& sourceChunk) {
279:       // Initialise the holder for a specific cache and script source.
280:       // This will hold on to the cached source chars in the event that
281:       // the cache is purged.
282:       MOZ_ASSERT(!cache_);
283:       MOZ_ASSERT(!sourceChunk_.valid());
284:       MOZ_ASSERT(!data_);
285: 
286:       cache_ = cache;
287:       sourceChunk_ = sourceChunk;
288:     }
