291:       // Take ownership of source chars now the cache is being purged. Remove
292:       // our reference to the ScriptSource which might soon be destroyed.
293:       MOZ_ASSERT(cache_);
294:       MOZ_ASSERT(sourceChunk_.valid());
295:       MOZ_ASSERT(!data_);
296: 
297:       cache_ = nullptr;
298:       sourceChunk_ = ScriptSourceChunk();
299: 
300:       data_ = std::move(data);
301:     }
